 1	import React, { FC, useState } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import FolderSelect from '@kubevirt-utils/components/FolderSelect/FolderSelect';
 6	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { getLabel, getName, getNamespace } from '@kubevirt-utils/resources/shared';
 9	import { Stack, StackItem } from '@patternfly/react-core';
10	import { VM_FOLDER_LABEL } from '@virtualmachines/tree/utils/constants';
11	
12	type MoveVMToFolderModalProps = {
13	  isOpen: boolean;
14	  onClose: () => void;
15	  onSubmit: (folderName: string) => Promise<V1VirtualMachine | void>;
16	  vm: V1VirtualMachine;
17	};
18	
19	const MoveVMToFolderModal: FC<MoveVMToFolderModalProps> = ({ isOpen, onClose, onSubmit, vm }) => {
20	  const { t } = useKubevirtTranslation();
21	  const [folderName, setFolderName] = useState<string>(getLabel(vm, VM_FOLDER_LABEL));
22	
23	  return (
24	    <TabModal<V1VirtualMachine>
25	      headerText={t('Move to folder')}
26	      isOpen={isOpen}
27	      onClose={onClose}
28	      onSubmit={() => onSubmit(folderName)}
29	      submitBtnText={t('Save')}
30	    >
31	      <Stack hasGutter>
32	        <StackItem>
33	          <Trans t={t}>
34	            Move <b>{getName(vm)}</b> VirtualMachine to folder
35	          </Trans>
36	        </StackItem>
37	        <StackItem>
38	          <FolderSelect
39	            isFullWidth
40	            namespace={getNamespace(vm)}
41	            selectedFolder={folderName}
42	            setSelectedFolder={setFolderName}
43	          />
44	        </StackItem>
45	      </Stack>
46	    </TabModal>
47	  );
48	};
49	
50	export default MoveVMToFolderModal;

